INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 100, 130011, "ヤマト", 3001100, "2030/01/01 14:59:59", 2, 0.0, 1, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 3001, 2.1);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 101, 130011, "ヤマト", 3001101, "2030/01/01 14:59:59", 2, 0.0, 4, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 3001, 5.68);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 102, 130011, "ヤマト", 3001102, "2030/01/01 14:59:59", 1, 0.0, 1, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 3001, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 100, 130211, "フブキ", 3002100, "2030/01/01 14:59:59", 1, 0.0, 1, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 3002, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 101, 130211, "フブキ", 3002101, "2030/01/01 14:59:59", 1, 0.0, 1, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 3002, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 102, 130211, "フブキ", 3002102, "2030/01/01 14:59:59", 2, 0.0, 5, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 3002, 8.53);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 103, 130211, "フブキ", 3002103, "2030/01/01 14:59:59", 1, 0.0, 7, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 3002, 5.67);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 104, 130211, "フブキ", 3002104, "2030/01/01 14:59:59", 1, 0.0, 1, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 3002, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 300, 130211, "フブキ", 3002300, "2030/01/01 14:59:59", 3, 0.0, 3, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3004, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 301, 130211, "フブキ", 3002400, "2030/01/01 14:59:59", 7, 0.0, 7, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 3005, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 200, 130211, "フブキ", 3003200, "2030/01/01 14:59:59", 1, 0.0, 2, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 3003, 4.4);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 201, 130211, "フブキ", 3003201, "2030/01/01 14:59:59", 7, 0.0, 7, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 3003, 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (-416.5, "2024/10/31 12:00:00", 202, 130211, "フブキ", 3003202, "2030/01/01 14:59:59", 2, 0.0, 1, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 3003, 5.6);
